import { describe, expect, it } from 'vitest';

import { ThothOathClient, type ThothOathFetcher } from '../src/thoth-oath-client';

describe('ThothOathClient', () => {
  it('calls oath CRUD routes with stable request shapes', async () => {
    const requests: Array<{ method: string; path: string; body: string }> = [];
    const fetcher: ThothOathFetcher = {
      async fetch(req) {
        const url = new URL(req.url);
        requests.push({
          method: req.method,
          path: url.pathname,
          body: req.method === 'POST' || req.method === 'PATCH' ? await req.text() : '',
        });
        if (req.method === 'GET') {
          return json({
            object: 'thoth.oath_ledger',
            ledgerPath: '/tmp/oaths.json',
            nonAuthoritative: true,
            oaths: [],
            activeOathCount: 0,
          });
        }
        if (req.method === 'POST') {
          return json({
            action: 'oath.proposed',
            oath: { id: 'oath_1' },
            telemetryEvent: { kind: 'oath.proposed', activeOathCount: 1 },
            nonAuthoritative: true,
            captureBoundary: 'separate',
            timerBoundary: 'gnosis-time',
          }, 201);
        }
        if (req.method === 'PATCH') {
          return json({
            action: 'oath.updated',
            oath: { id: 'oath_1', effectiveStatus: 'cleared', remainingMs: 0 },
            nonAuthoritative: true,
          });
        }
        return json({
          action: 'oath.deleted',
          id: 'oath_1',
          nonAuthoritative: true,
          auditWarning: 'delete removes the local operator ledger entry',
        });
      },
    };
    const client = new ThothOathClient({
      endpoint: fetcher,
      baseUrl: 'http://server/',
    });

    await expect(client.list()).resolves.toMatchObject({
      object: 'thoth.oath_ledger',
      nonAuthoritative: true,
    });
    await expect(
      client.create({ invariant: 'hold the control plane', durationTicks: 2 }),
    ).resolves.toMatchObject({ action: 'oath.proposed' });
    await expect(
      client.update('oath_1', { status: 'cleared', clearReason: 'operator' }),
    ).resolves.toMatchObject({ action: 'oath.updated' });
    await expect(client.delete('oath_1')).resolves.toMatchObject({
      action: 'oath.deleted',
    });

    expect(requests).toEqual([
      { method: 'GET', path: '/v1/thoth/oaths', body: '' },
      {
        method: 'POST',
        path: '/v1/thoth/oaths',
        body: '{"invariant":"hold the control plane","durationTicks":2}',
      },
      {
        method: 'PATCH',
        path: '/v1/thoth/oaths/oath_1',
        body: '{"status":"cleared","clearReason":"operator"}',
      },
      { method: 'DELETE', path: '/v1/thoth/oaths/oath_1', body: '' },
    ]);
  });

  it('throws with status and response body on oath route failures', async () => {
    const client = new ThothOathClient({
      baseUrl: 'http://server',
      endpoint: {
        async fetch() {
          return new Response('not configured', { status: 404 });
        },
      },
    });

    await expect(client.list()).rejects.toThrow(
      'ThothOathClient GET /v1/thoth/oaths: 404 not configured',
    );
  });
});

function json(value: unknown, status = 200): Response {
  return new Response(JSON.stringify(value), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });
}
